class SAMLUserManager:
    @staticmethod
    def get_or_create_user(name_id, attributes):
        email = attributes.get('email', attributes.get('mail', attributes.get('emailAddress', '')))
        first_name = attributes.get('firstName', attributes.get('givenName', ''))
        last_name = attributes.get('lastName', attributes.get('surname', attributes.get('sn', '')))
        
        username = SAMLUserManager._generate_username(name_id, email)
        
        try:
            user = User.objects.get(username=username)
        except User.DoesNotExist:
            user = User.objects.create_user(
                username=username,
                email=email if email else '',
                first_name=first_name if first_name else '',
                last_name=last_name if last_name else ''
            )
            user.set_unusable_password()
            user.save()
        
        if email and user.email != email:
            user.email = email
        if first_name and user.first_name != first_name:
            user.first_name = first_name
        if last_name and user.last_name != last_name:
            user.last_name = last_name
        
        user.save()
        
        return user
    
    @staticmethod
    def _generate_username(name_id, email):
        if email:
            base_username = email.split('@')[0]
        else:
            base_username = name_id
        
        base_username = ''.join(c if c.isalnum() or c in ['_', '-'] else '_' for c in base_username)
        base_username = base_username[:30]
        
        username = base_username
        counter = 1
        while User.objects.filter(username=username).exists():
            suffix = f"_{counter}"
            username = base_username[:30-len(suffix)] + suffix
            counter += 1
        
        return username


@csrf_exempt
@require_http_methods(["POST"])
def saml_acs(request):
    saml_response_encoded = request.POST.get('SAMLResponse', '')
    relay_state = request.POST.get('RelayState', '/')
    
    if not saml_response_encoded:
        return HttpResponseBadRequest("Missing SAMLResponse parameter")
    
    saml_response = SAMLResponse(saml_response_encoded)
    
    if not saml_response.process():
        return HttpResponseBadRequest("Invalid SAML response")
    
    user = SAMLUserManager.get_or_create_user(
        saml_response.name_id,
        saml_response.attributes
    )
    
    request.session['saml_name_id'] = saml_response.name_id
    request.session['saml_session_index'] = saml_response.session_index
    request.session['saml_attributes'] = saml_response.attributes
    
    user.backend = 'django.contrib.auth.backends.ModelBackend'
    login(request, user)
    
    return redirect(relay_state)


